import{_ as a,o as r,c as t,a3 as o}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"50. Meal Breaks","description":"","frontmatter":{"title":"50. Meal Breaks","eba":"Health Allied & Managers Admin 2021-2025","topics":["hours","shift-work","breaks","on-call"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/hours-of-work/50-meal-breaks.md","filePath":"ebas/has-managers-admin/common-terms/hours-of-work/50-meal-breaks.md"}'),n={name:"ebas/has-managers-admin/common-terms/hours-of-work/50-meal-breaks.md"};function s(l,e,m,i,d,h){return r(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="_50-meal-breaks" tabindex="-1">50. Meal Breaks <a class="header-anchor" href="#_50-meal-breaks" aria-label="Permalink to &quot;50. Meal Breaks&quot;">​</a></h1><p><strong>50.1</strong> An Employee will not be required to work more than 5 hours continuously without a meal interval of not less than 30 minutes and not more than 60 minutes.</p><p><strong>50.2</strong> Meal breaks will not be regarded as time worked.</p><p><strong>50.3</strong> Employees who are called back to work from their rostered meal break will be granted a meal break of not less than 20 minutes during the remainder of their shift. Such meal break will be counted as time worked.</p><p><strong>50.4</strong> Night Duty</p><p><strong>(a)</strong> Employees who are not relieved from night duty (and on-call) during the rostered meal break will be granted a meal break of not less than 20 minutes, to be commenced after completing three hours and not more than five hours of duty. Such meal break will be counted as time worked.</p><p><strong>(b)</strong> The arrangement in subclause 50.4(a) may also be adopted in any case where there is mutual agreement between the Employer and Employee.</p><p>Plain language terms: meal break, lunch break.</p>',8)])])}const b=a(n,[["render",s]]);export{c as __pageData,b as default};
